// Mes anterior completo en zona Madrid: [last_month_ymd, last_month_end_ymd).
const now = new Date();
function madridYMD(d){ return d.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function ymdToDate(s){ return new Date(s + 'T00:00:00Z'); }
function ymdFromDate(d){ return d.toISOString().substring(0,10); }
const todayYMD = madridYMD(now);
const [yy, mm] = todayYMD.split('-');
const monthYMD = `${yy}-${mm}-01`;
const _prev    = ymdToDate(monthYMD); _prev.setUTCMonth(_prev.getUTCMonth() - 1);
const lastMonthYMD    = ymdFromDate(_prev);
const lastMonthEndYMD = monthYMD;
return [{ json: { last_month_ymd: lastMonthYMD, last_month_end_ymd: lastMonthEndYMD } }];

// Calcula top 8 orgs del mes anterior y prepara CSV de IDs para resolver nombres.
const dates = $('Calcular fechas').first().json;
const tickets = $input.all().map(i => i.json).filter(Boolean);
const m = new Map();
for (const t of tickets) {
  if (!t || !t.organization_id) continue;
  m.set(t.organization_id, (m.get(t.organization_id) || 0) + 1);
}
const top = [...m.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8);
const ids = top.map(([id])=>id);
return [{ json: { ...dates, _top_raw: top, org_ids_csv: ids.join(',') || '0', _ticket_count: tickets.length } }];

// Resuelve nombres + GUARDA EL RESULTADO EN STATIC DATA del workflow.
// El webhook leerá esta caché y responderá al instante.
const acc  = $('Calcular Top').first().json;
const body = $input.first().json || {};
const orgs = Array.isArray(body.organizations) ? body.organizations : [];
const orgMap = new Map();
for (const o of orgs) { if (o && o.id) orgMap.set(o.id, o.name); }
const top_orgs_last_month = (acc._top_raw || []).map(([id, count]) => ({
  name: orgMap.get(id) || `Organización ${id}`,
  count
}));
const payload = {
  generated_at:       new Date().toISOString(),
  last_month_ymd:     acc.last_month_ymd,
  last_month_end_ymd: acc.last_month_end_ymd,
  ticket_count:       acc._ticket_count,
  top_orgs_last_month
};
const staticData = $getWorkflowStaticData('global');
staticData.cached_payload = payload;
staticData.cached_at      = payload.generated_at;
return [{ json: { saved: true, ...payload } }];

// Lee el último resultado cacheado por el Schedule Trigger.
// Si la caché está vacía (primer arranque), devuelve estructura vacía y _stale=true.
const staticData = $getWorkflowStaticData('global');
const cached = staticData.cached_payload || null;
if (!cached) {
  return [{ json: {
    generated_at: null,
    cached_at: null,
    _stale: true,
    _hint: 'Cache vacía. Lanza manualmente el Schedule Trigger una vez.',
    top_orgs_last_month: []
  } }];
}
return [{ json: { ...cached, cached_at: staticData.cached_at, _stale: false } }];
